 1	import React, { FC, memo } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Button, GridItem, TextInput } from '@patternfly/react-core';
 5	import { MinusCircleIcon } from '@patternfly/react-icons';
 6	
 7	export const AnnotationsModalRow: FC<{
 8	  annotation: { key: string; value: string };
 9	  onChange: ({ key, value }: { key: string; value: string }) => void;
10	  onDelete: () => void;
11	}> = memo(({ annotation, onChange, onDelete }) => {
12	  const { t } = useKubevirtTranslation();
13	  return (
14	    <>
15	      <GridItem span={5}>
16	        <TextInput
17	          aria-label={t('annotation key')}
18	          autoFocus
19	          className="annotation-form-input"
20	          isRequired
21	          maxLength={255}
22	          onChange={(_event, newKey) => onChange({ ...annotation, key: newKey })}
23	          placeholder={t('annotation key')}
24	          size={1}
25	          type="text"
26	          value={annotation.key}
27	        />
28	      </GridItem>
29	      <GridItem span={5}>
30	        <TextInput
31	          aria-label={t('annotation value')}
32	          className="annotation-form-input"
33	          isRequired
34	          maxLength={255}
35	          onChange={(_event, newValue) => onChange({ ...annotation, value: newValue })}
36	          placeholder={t('annotation value')}
37	          type="text"
38	          value={annotation.value}
39	        />
40	      </GridItem>
41	      <GridItem span={2}>
42	        <Button onClick={() => onDelete()} variant="plain">
43	          <MinusCircleIcon />
44	        </Button>
45	      </GridItem>
46	    </>
47	  );
48	});
49	AnnotationsModalRow.displayName = 'AnnotationModalRow';

